// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.equivalence;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Map;
import java.util.Set;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

class EvaluationOutcomeTest {

	@Test
	void successMaterializesEveryObservation() {
		BindingSetSnapshot row = row("x", "value");
		EvaluationOutcome outcome = EvaluationOutcome.success(List.of(row, row));

		assertEquals(List.of(row, row), outcome.getSequence());
		assertEquals(Map.of(row, 2L), outcome.getBag());
		assertEquals(Set.of(row), outcome.getSet());
		assertFalse(outcome.isEmpty());
		assertFalse(outcome.hasError());
		assertNull(outcome.getError());
		assertEquals("{" + row + "=2}", outcome.toString());
		assertTrue(outcome.sameAs(EvaluationOutcome.success(List.of(row, row)), ObservationMode.BAG));
		assertTrue(outcome.sameAs(EvaluationOutcome.success(List.of(row)), ObservationMode.SET));
		assertTrue(outcome.sameAs(EvaluationOutcome.success(List.of(row)), ObservationMode.ASK));
		assertFalse(outcome.sameAs(EvaluationOutcome.success(List.of(row)), ObservationMode.SEQUENCE));
	}

	@Test
	void emptyAndErrorOutcomesStayDistinct() {
		EvaluationOutcome empty = EvaluationOutcome.success(List.of());
		EvaluationOutcome withMessage = EvaluationOutcome.error(new IllegalStateException("broken"));
		EvaluationOutcome withoutMessage = EvaluationOutcome.error(new IllegalArgumentException());

		assertTrue(empty.isEmpty());
		assertEquals("{}", empty.toString());
		assertTrue(withMessage.hasError());
		assertEquals("java.lang.IllegalStateException: broken", withMessage.getError());
		assertEquals("ERROR(java.lang.IllegalStateException: broken)", withMessage.toString());
		assertEquals("java.lang.IllegalArgumentException", withoutMessage.getError());
		for (ObservationMode mode : ObservationMode.values()) {
			assertFalse(withMessage.sameAs(empty, mode));
			assertTrue(withMessage.sameAs(withoutMessage, mode));
		}
	}

	private static BindingSetSnapshot row(String name, String value) {
		MapBindingSet bindings = new MapBindingSet();
		bindings.setBinding(name, SimpleValueFactory.getInstance().createLiteral(value));
		return BindingSetSnapshot.copyOf(bindings);
	}
}
